-- Create the linkedin_industries reference table
CREATE TABLE IF NOT EXISTS public.linkedin_industries (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  sector text NOT NULL,
  industry_group text NOT NULL,
  sub_industry text,
  display_name text NOT NULL,
  slug text NOT NULL UNIQUE,
  sector_slug text NOT NULL,
  display_order int NOT NULL DEFAULT 0,
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now()
);

-- Indexes for common query patterns
CREATE INDEX IF NOT EXISTS idx_linkedin_industries_sector ON public.linkedin_industries (sector);
CREATE INDEX IF NOT EXISTS idx_linkedin_industries_industry_group ON public.linkedin_industries (industry_group);
CREATE INDEX IF NOT EXISTS idx_linkedin_industries_sector_slug ON public.linkedin_industries (sector_slug);
CREATE INDEX IF NOT EXISTS idx_linkedin_industries_display_name ON public.linkedin_industries (display_name);

-- Enable RLS (public read, admin write)
ALTER TABLE public.linkedin_industries ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can read linkedin_industries"
  ON public.linkedin_industries FOR SELECT
  USING (true);

